import{_ as a,o as t,c as p,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"3.13.体积规则","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/3.战斗规则/3.13.体积规则.md","filePath":"1.基础规则/3.战斗规则/3.13.体积规则.md"}'),s={name:"1.基础规则/3.战斗规则/3.13.体积规则.md"};function o(_,e,d,l,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"_3-13-体积规则",tabindex:"-1"},[b("3.13.体积规则 "),r("a",{class:"header-anchor",href:"#_3-13-体积规则","aria-label":'Permalink to "3.13.体积规则"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新秩序006")])])],-1),n('<h1 id="体积规则" tabindex="-1">体积规则 <a class="header-anchor" href="#体积规则" aria-label="Permalink to &quot;体积规则&quot;">​</a></h1><p>体积规则</p><p>一般而言，体积是指体积对于人物的体型判断。同理，适用于人类的体型判断也可以以此标准用于其他物体上。对于载具而言，体积带来的修正效果需要单独计算，并未在载具中标注。</p><p>空间体积<br> 对于异空间或者储物空间类能力，其能装载的体积与立方米物品的对应关系为：每1立方米可装载3体积的物品</p><p>单位体积<br> 普通人的体积在5左右，一般视为5，减少1体积相当于减少40cm左右。也可以使未成年人在建卡时最多为体积4。<br> 体积的上升会为人物提供：</p><p>更多的血量（每提升1点便同步提升1点）<br> 更大的迈步距离（表现在速度上，每提升1点便同步提升1点）<br> 更远的触及范围（每提升1点体积便加0.33米触及范围）</p><p>体积的下降（至少小于4）会为人物提供：<br> 更多的基础闪避防御（每提升1点便同步提升1点）<br> 相应的，体积的上升和下降都会有负面影响。</p><p>体积的上升会导致：<br> 当人物体积大于7点时，人物在倒地后爬起需要一个整轮动作</p><p>体积的下降会导致：<br> 武器力量需求增加（武器体积不大于人物体积时增加1点；大于时增加3点）<br> 血量下降（每下降1点就同步下降1点）<br> 更小的迈步距离（表现在速度上，每下降1点便同步下降1点）</p><p>体积区间<br> 再某位范围内的体积视为对于区间的体积类型，会有不同的正面和负面效果。<br> 1体积以下：微型<br> 1-3体积：小型<br> 4-12体积：中型<br> 12-26体积：大型<br> 26-50：巨型<br> 51+：超巨型</p><p>体积所能带来的优势与劣势<br> 优势：<br> 1、单位每具有6点体积，其就会获得1点天生防御/盔甲防御（对于载具）与1点强韧豁免加值，这部分加值是体积加值。<br> 2、单位每具有6点体积，其在进行攻击时就获得1点威猛。</p><p>劣势：<br> 单位每具有6点体积，其就在反射豁免上承受1点环境减值。<br> 单位每具有6点体积，其他单位在对其进行攻击时，就额外获得1点高速。<br> 单位每具有6点体积，其就在隐秘技能检定上承受1点减值。</p><hr><p>Copyright © 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',14)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
